namespace sv_d34ee16bdec5466b98bc6c47138e141e.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_d34ee16bdec5466b98bc6c47138e141e.Services

<button class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    }
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private string TruncateDescription(string desc) =>
        desc.Length > 40 ? desc[..37] + "..." : desc;
}

.channel-item {
    display: block;
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: none;
    background: transparent;
    text-align: left;
    cursor: pointer;
    border-radius: 6px;
    margin-bottom: 2px;
    transition: background-color 0.15s;
    color: #c4c9d4;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background: rgba(99, 132, 255, 0.2);
    color: #fff;
}

.channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e04e4e;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 0.1rem 0.4rem;
    border-radius: 10px;
    min-width: 1.2rem;
    text-align: center;
    flex-shrink: 0;
}

.channel-desc {
    font-size: 0.75rem;
    color: #8b919a;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.message-input-area {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem;
    border-top: 1px solid #3a3d44;
    background: #2b2d33;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #4a4d55;
    border-radius: 8px;
    padding: 0.5rem 0.75rem;
    background: #1e1f24;
    color: #e0e0e0;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #6384ff;
}

.send-btn {
    padding: 0.5rem 1rem;
    background: #6384ff;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.85rem;
    transition: background-color 0.15s, opacity 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #4f6de8;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_d34ee16bdec5466b98bc6c47138e141e.Services

<div class="chat-message" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions-row">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="action-bar">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
                💬 Reply
            </button>
            <button class="action-btn" title="Add reaction" @onclick="ToggleEmojiPicker">
                🙂 React
            </button>
        </div>

        @if (showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in commonEmojis)
                {
                    <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.chat-message {
    position: relative;
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    transition: background-color 0.12s;
}

.chat-message:hover {
    background: rgba(255, 255, 255, 0.04);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #e0e0e0;
}

.timestamp {
    font-size: 0.75rem;
    color: #8b919a;
}

.message-content {
    font-size: 0.9rem;
    color: #d0d4dc;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 0.15rem 0.45rem;
    border-radius: 12px;
    background: rgba(99, 132, 255, 0.15);
    border: 1px solid rgba(99, 132, 255, 0.3);
    font-size: 0.8rem;
    color: #c4c9d4;
    cursor: default;
}

.thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    background: none;
    border: none;
    color: #6384ff;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 0;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -0.75rem;
    right: 0.5rem;
    display: flex;
    gap: 2px;
    background: #36383f;
    border: 1px solid #4a4d55;
    border-radius: 6px;
    padding: 0.15rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.action-btn {
    background: transparent;
    border: none;
    color: #c4c9d4;
    font-size: 0.78rem;
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
    cursor: pointer;
    white-space: nowrap;
}

.action-btn:hover {
    background: rgba(255, 255, 255, 0.1);
}

.emoji-picker {
    position: absolute;
    top: -2.5rem;
    right: 0.5rem;
    display: flex;
    gap: 2px;
    background: #36383f;
    border: 1px solid #4a4d55;
    border-radius: 8px;
    padding: 0.3rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 11;
}

.emoji-btn {
    background: transparent;
    border: none;
    font-size: 1.2rem;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.emoji-btn:hover {
    background: rgba(255, 255, 255, 0.12);
}

