.chat-message {
    position: relative;
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    transition: background-color 0.12s;
}

.chat-message:hover {
    background: rgba(255, 255, 255, 0.04);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #e0e0e0;
}

.timestamp {
    font-size: 0.75rem;
    color: #8b919a;
}

.message-content {
    font-size: 0.9rem;
    color: #d0d4dc;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 0.15rem 0.45rem;
    border-radius: 12px;
    background: rgba(99, 132, 255, 0.15);
    border: 1px solid rgba(99, 132, 255, 0.3);
    font-size: 0.8rem;
    color: #c4c9d4;
    cursor: default;
}

.thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    background: none;
    border: none;
    color: #6384ff;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 0;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -0.75rem;
    right: 0.5rem;
    display: flex;
    gap: 2px;
    background: #36383f;
    border: 1px solid #4a4d55;
    border-radius: 6px;
    padding: 0.15rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.action-btn {
    background: transparent;
    border: none;
    color: #c4c9d4;
    font-size: 0.78rem;
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
    cursor: pointer;
    white-space: nowrap;
}

.action-btn:hover {
    background: rgba(255, 255, 255, 0.1);
}

.emoji-picker {
    position: absolute;
    top: -2.5rem;
    right: 0.5rem;
    display: flex;
    gap: 2px;
    background: #36383f;
    border: 1px solid #4a4d55;
    border-radius: 8px;
    padding: 0.3rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 11;
}

.emoji-btn {
    background: transparent;
    border: none;
    font-size: 1.2rem;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.emoji-btn:hover {
    background: rgba(255, 255, 255, 0.12);
}

