arguments.file_text:
@using sv_d34ee16bdec5466b98bc6c47138e141e.Services

<aside class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <nav class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelListItem Channel="channel"
                             IsActive="channel.Id == SelectedChannelId"
                             OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </nav>
</aside>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background: #1e1f24;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #3a3d44;
}

.sidebar-header {
    padding: 0.85rem 0.75rem;
    border-bottom: 1px solid #3a3d44;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #e0e0e0;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.4rem;
}

@using sv_d34ee16bdec5466b98bc6c47138e141e.Services
@inject IJSRuntime JS

<section class="message-area">
    @if (CurrentChannel is not null)
    {
        <header class="area-header">
            <h2># @CurrentChannel.Name</h2>
            <span class="area-description">@CurrentChannel.Description</span>
        </header>

        <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages...</div>
            }
            @foreach (var msg in Messages)
            {
                <ChatMessage Message="msg"
                             ThreadSummary="GetThreadSummary(msg.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{CurrentChannel.Name}")"
                      ButtonText="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="empty-state">
            <p>Select a channel to start chatting</p>
        </div>
    }
</section>

@code {
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[b-message-area]')?.scrollTop ?? -1");
        if (scrollTop <= 1 && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2b2d33;
}

.area-header {
    padding: 0.65rem 1rem;
    border-bottom: 1px solid #3a3d44;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
    color: #e0e0e0;
}

.area-description {
    font-size: 0.8rem;
    color: #8b919a;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

.loading-indicator {
    text-align: center;
    padding: 0.5rem;
    color: #8b919a;
    font-size: 0.8rem;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #8b919a;
    font-size: 1rem;
}

@using sv_d34ee16bdec5466b98bc6c47138e141e.Services

<aside class="thread-panel">
    <header class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </header>

    @if (RootMessage is not null)
    {
        <div class="root-message-quote">
            <div class="quote-author">@RootMessage.Author</div>
            <div class="quote-content">@RootMessage.Content</div>
        </div>

        <div class="thread-replies">
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonText="Reply"
                      OnSubmit="OnSendReply" />
    }
</aside>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

