toolArgs.file_text:
@using sv_d34ee16bdec5466b98bc6c47138e141e.Services

<aside class="thread-panel">
    <header class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </header>

    @if (RootMessage is not null)
    {
        <div class="root-message-quote">
            <div class="quote-author">@RootMessage.Author</div>
            <div class="quote-content">@RootMessage.Content</div>
        </div>

        <div class="thread-replies">
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonText="Reply"
                      OnSubmit="OnSendReply" />
    }
</aside>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #25272c;
    border-left: 1px solid #3a3d44;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.65rem 0.75rem;
    border-bottom: 1px solid #3a3d44;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #e0e0e0;
}

.close-btn {
    background: transparent;
    border: none;
    color: #8b919a;
    font-size: 1rem;
    cursor: pointer;
    padding: 0.2rem 0.4rem;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: rgba(255, 255, 255, 0.1);
    color: #e0e0e0;
}

.root-message-quote {
    padding: 0.6rem 0.75rem;
    margin: 0.5rem;
    background: rgba(255, 255, 255, 0.04);
    border-left: 3px solid #6384ff;
    border-radius: 0 6px 6px 0;
}

.quote-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #e0e0e0;
    margin-bottom: 0.15rem;
}

.quote-content {
    font-size: 0.85rem;
    color: #b0b5be;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 0.25rem 0;
}

.thread-reply {
    padding: 0.4rem 0.75rem;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 0.4rem;
    margin-bottom: 0.1rem;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #e0e0e0;
}

.reply-time {
    font-size: 0.72rem;
    color: #8b919a;
}

.reply-content {
    font-size: 0.85rem;
    color: #d0d4dc;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

