@page "/chat"
@using sv_d34ee16bdec5466b98bc6c47138e141e.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-col">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-col @(threadOpen ? "with-thread" : "")">
        <MessageArea CurrentChannel="currentChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     IsLoadingMore="isLoadingMore"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnReact="AddReaction"
                     OnLoadMore="LoadMoreMessages" />
    </div>

    @if (threadOpen)
    {
        <div class="thread-col">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private Channel? currentChannel;
    private int? selectedChannelId;

    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        currentChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadSummaries = new();
        hasMoreMessages = true;
        CloseThreadSync();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count >= PageSize;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || !hasMoreMessages || selectedChannelId is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            BuildThreadSummaries();
        }
        hasMoreMessages = older.Count >= PageSize;
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannelId is null) return;

        var msg = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadMessages = await ChatService.GetThreadAsync(messageId);
        threadOpen = true;
    }

    private void CloseThread()
    {
        CloseThreadSync();
        StateHasChanged();
    }

    private void CloseThreadSync()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendReply(string content)
    {
        if (threadRootMessage is null || selectedChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannelId.Value, content, threadRootMessage.Id);
        threadMessages.Add(reply);

        // Update thread summary in the main view
        if (threadSummaries.ContainsKey(threadRootMessage.Id))
        {
            var existing = threadSummaries[threadRootMessage.Id];
            threadSummaries[threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update: find the message and add/update the reaction
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var reaction = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (reaction is not null)
            {
                if (!reaction.Users.Contains("You"))
                    reaction.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from messages that have replies
        var replyGroups = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value);

        threadSummaries = new();
        foreach (var group in replyGroups)
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    background: #2b2d33;
    color: #e0e0e0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.sidebar-col {
    width: 20%;
    min-width: 180px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-col {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
}

.main-col.with-thread {
    /* Constrain when thread panel is open */
}

.thread-col {
    width: 25%;
    min-width: 260px;
    max-width: 400px;
    flex-shrink: 0;
}

