@using sv_d34ee16bdec5466b98bc6c47138e141e.Services
@inject IJSRuntime JS

<section class="message-area">
    @if (CurrentChannel is not null)
    {
        <header class="area-header">
            <h2># @CurrentChannel.Name</h2>
            <span class="area-description">@CurrentChannel.Description</span>
        </header>

        <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages...</div>
            }
            @foreach (var msg in Messages)
            {
                <ChatMessage Message="msg"
                             ThreadSummary="GetThreadSummary(msg.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{CurrentChannel.Name}")"
                      ButtonText="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="empty-state">
            <p>Select a channel to start chatting</p>
        </div>
    }
</section>

@code {
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[b-message-area]')?.scrollTop ?? -1");
        if (scrollTop <= 1 && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

