        ThreadSummaries.GetValueOrDefault(messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-d34ee16bdec5466b98bc6c47138e141e/Components/Chat/MessageArea.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
        }

        // Re-attach scroll listener whenever the list element might have re-rendered
        if (jsModule is not null && dotNetRef is not null && CurrentChannel is not null)
        {
            await jsModule.InvokeVoidAsync("attachScrollListener", messageListRef, dotNetRef);
        }
    }

