let currentElement = null;
let currentHandler = null;

export function attachScrollListener(element, dotNetRef) {
    detachScrollListener();

    currentElement = element;
    currentHandler = () => {
        if (element.scrollTop <= 1) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    };
    element.addEventListener('scroll', currentHandler, { passive: true });
}

export function detachScrollListener() {
    if (currentElement && currentHandler) {
        currentElement.removeEventListener('scroll', currentHandler);
        currentElement = null;
        currentHandler = null;
    }
}

